public class Counter {
    private static boolean isCounting = false;
    private static int counter = 0;

    public static void count(int value) throws InterruptedException {
        while (isCounting) {
            sleep(10);
        }
        isCounting = true;
        while (value > 0) {
            counter = counter + value;
            value--;
        }
        isCounting = false;
    }
}

