interface Fortbewegungsmittel {
    void bewegen();
}

abstract class Boot implements Fortbewegungsmittel {
    public void beschleunigen() {
        System.out.println("Das Boot beschleunigt.");
    }
}

class Segelboot extends Boot {
    @Override
    public void bewegen() {
        System.out.println("Das Segelboot bewegt sich.");
    }

    public void beschleunigen() {
        System.out.println("Das Boot setzt die Segel.");
    }
}
